import React, { useState } from "react";
import { Camera, CameraResultType, CameraSource } from "@capacitor/camera";

function App() {
  const [photo, setPhoto] = useState(null);
  const [uploading, setUploading] = useState(false);

  const takePhoto = async () => {
    try {
      const image = await Camera.getPhoto({
        quality: 90,
        allowEditing: true,
        resultType: CameraResultType.Uri,
        source: CameraSource.Camera,
        saveToGallery: true,
      });
      setPhoto(image.webPath); // 촬영 이미지 경로 저장
    } catch (err) {
      console.error("카메라 오류:", err);
    }
  };

  const deletePhoto = () => {
    setPhoto(null); // 사진 상태 초기화
  };

  const uploadPhoto = async () => {
    if (!photo) return;
    setUploading(true);
    setTimeout(() => {
      setUploading(false);
      alert("서버 전송이 완료되었습니다!");
      setPhoto(null);
    }, 1500); // 서버 전송 시뮬레이션
  };

  const useHover = () => {
    const [hover, setHover] = useState(false);
    const onMouseEnter = () => setHover(true);
    const onMouseLeave = () => setHover(false);
    return [hover, { onMouseEnter, onMouseLeave }];
  };

  const [mainBtnHover, mainBtnHoverEvents] = useHover();
  const [uploadBtnHover, uploadBtnHoverEvents] = useHover();

  return (
    <div style={wrapperStyle}>
      <header style={headerStyle}>
        <div style={headerContentStyle}>
          <h1 style={headerTitleStyle}>Capacitor Camera</h1>
        </div>
      </header>

      <main style={mainStyle}>
        <div style={photoCardStyle}>
          {photo ? (
            <>
              <img src={photo} alt="Preview" style={imageStyle} />
              <button onClick={deletePhoto} style={closeButtonStyle}>
                ✕
              </button>
            </>
          ) : (
            <div style={placeholderStyle}>
              <div style={placeholderIconStyle}>📷</div>
              <p style={placeholderTextStyle}>촬영된 사진 없음</p>
              <p style={placeholderSubTextStyle}>
                하단의 버튼을 눌러 사진을 찍어주세요
              </p>
            </div>
          )}
        </div>

        <div style={statusStyle}>
          {photo
            ? "서버로 전송할 준비가 되었습니다."
            : "업로드할 사진을 촬영해주세요."}
        </div>
      </main>

      <footer style={footerStyle}>
        {!photo ? (
          <button
            onClick={takePhoto}
            style={{
              ...mainButtonStyle,
              ...(mainBtnHover ? mainButtonStyleHover : {}),
            }}
            {...mainBtnHoverEvents}
          >
            사진 찍기
          </button>
        ) : (
          <button
            onClick={uploadPhoto}
            style={{
              ...mainButtonStyle,
              backgroundColor: "#28a745",
              ...(uploadBtnHover
                ? { backgroundColor: "#218838", transform: "scale(1.02)" }
                : {}),
              ...(uploading ? { opacity: 0.7 } : {}),
            }}
            disabled={uploading}
            {...uploadBtnHoverEvents}
          >
            {uploading ? "전송 중..." : "서버로 전송하기"}
          </button>
        )}
      </footer>
    </div>
  );
}

const wrapperStyle = {
  backgroundColor: "#f0f2f5",
  minHeight: "100vh",
  display: "flex",
  flexDirection: "column",
  fontFamily:
    "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif",
};

const headerStyle = {
  paddingTop: "calc(env(safe-area-inset-top, 44px) + 10px)",
  paddingBottom: "15px",
  backgroundColor: "#fff",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  borderBottom: "1px solid #eee",
  boxShadow: "0 2px 10px rgba(0,0,0,0.05)",
};

const headerContentStyle = {
  display: "flex",
  alignItems: "center",
  gap: "10px",
};
const headerTitleStyle = {
  fontSize: "22px",
  margin: 0,
  fontWeight: "bold",
  color: "#333",
};

const mainStyle = {
  flex: 1,
  padding: "30px 20px",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};

const photoCardStyle = {
  width: "100%",
  maxWidth: "380px",
  aspectRatio: "3/4",
  backgroundColor: "#fff",
  borderRadius: "20px",
  boxShadow: "0 8px 20px rgba(0,0,0,0.1)",
  position: "relative",
  overflow: "hidden",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
};

const imageStyle = { width: "100%", height: "100%", objectFit: "cover" };

const placeholderStyle = { textAlign: "center", padding: "40px" };
const placeholderIconStyle = {
  fontSize: "60px",
  color: "#ced4da",
  marginBottom: "15px",
};
const placeholderTextStyle = {
  margin: "0 0 5px 0",
  color: "#495057",
  fontSize: "18px",
  fontWeight: "bold",
};
const placeholderSubTextStyle = {
  margin: 0,
  color: "#868e96",
  fontSize: "14px",
};

const closeButtonStyle = {
  position: "absolute",
  top: "10px",
  right: "10px",
  width: "35px",
  height: "35px",
  borderRadius: "50%",
  backgroundColor: "rgba(0,0,0,0.6)",
  color: "#fff",
  border: "none",
  cursor: "pointer",
  fontSize: "18px",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  zIndex: 10,
};

const statusStyle = {
  marginTop: "25px",
  color: "#495057",
  fontSize: "15px",
  fontWeight: "500",
};

const footerStyle = {
  padding: "20px 20px calc(env(safe-area-inset-bottom) + 20px)",
  backgroundColor: "#fff",
  borderTop: "1px solid #eee",
};

const mainButtonStyle = {
  width: "100%",
  padding: "18px",
  borderRadius: "15px",
  border: "none",
  backgroundColor: "#007bff",
  color: "#fff",
  fontSize: "18px",
  fontWeight: "bold",
  cursor: "pointer",
  transition: "all 0.2s ease-in-out",
  boxShadow: "0 4px 6px rgba(0,123,255,0.3)",
};

const mainButtonStyleHover = {
  backgroundColor: "#0056b3",
  transform: "scale(1.02)",
};

export default App;
